export const meta = {
  name: 'nesy-research-review',
  description: 'Adversarially verify the NeSy study: claims vs raw data, methodology, code correctness',
  phases: [
    { title: 'Review', detail: 'parallel reviewers: numbers, methodology, code' },
    { title: 'Verify', detail: 'adversarially verify each flagged issue' },
  ],
}

const ROOT = '/workspaces/neural-symbolic-ai-41f3-claude'

const ISSUE_SCHEMA = {
  type: 'object',
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          severity: { type: 'string', enum: ['critical', 'major', 'minor', 'nit'] },
          location: { type: 'string', description: 'file:line or REPORT.md section' },
          claim: { type: 'string', description: 'the specific claim or code under question' },
          problem: { type: 'string', description: 'what is wrong or unverified' },
          evidence: { type: 'string', description: 'concrete evidence from files / numbers' },
        },
        required: ['severity', 'location', 'problem', 'evidence'],
      },
    },
    summary: { type: 'string' },
  },
  required: ['findings', 'summary'],
}

phase('Review')
const reviewers = [
  {
    key: 'numbers',
    prompt: `You are a skeptical reviewer. Verify EVERY numerical claim in ${ROOT}/REPORT.md and ${ROOT}/README.md against the ground-truth data in ${ROOT}/results/stats.json and ${ROOT}/results/raw/*.json. Recompute aggregates yourself if needed by reading the raw JSON (you may use Bash with: source ${ROOT}/.venv/bin/activate && python -c '...'). Check: data-efficiency table (E1), grounding numbers (E2/E5), the 99.0%->0.1% collapse, the mitigation table (aux_k1 2.2%->97.7%), the OOD table (0.00 / 0.957 / 0.937), and all p-values / Cohen's d / Welch tests. Flag ANY mismatch between a stated number and the data, even small ones. Report findings as structured issues.`,
  },
  {
    key: 'methodology',
    prompt: `You are an adversarial methodology reviewer (NeurIPS area chair). Read ${ROOT}/REPORT.md, ${ROOT}/planning.md, and the code in ${ROOT}/src/. Hunt for: data leakage (does NeSy/neural training touch true digit labels? check src/train.py and src/data.py), train/test contamination, whether the Hungarian-aligned grounding metric is correctly described and used, whether statistical tests are appropriate (Welch, Holm, the H4 correlation caveat), overclaiming vs evidence, and any unfair baseline framing (e.g. neural-only OOD=0). Verify the modular-addition shortcut argument is mathematically correct ((d+5) symmetry). Report structured issues with severity.`,
  },
  {
    key: 'code',
    prompt: `You are a careful code reviewer. Read ${ROOT}/src/models.py, train.py, data.py, run_experiments.py, analyze.py. Look for correctness bugs that would invalidate results: is nesy_sum_logprob a correct convolution (sums to 1)? is the modular reduction correct? does evaluate() compute grounding/Hungarian correctly? does compose_number_logprob compute place-value correctly? any train/eval label leakage, off-by-one, or seed issues? You may run quick checks with Bash (source ${ROOT}/.venv/bin/activate). Report structured issues with severity and concrete evidence.`,
  },
]

const reviews = await parallel(reviewers.map(r => () =>
  agent(r.prompt, { label: `review:${r.key}`, phase: 'Review', schema: ISSUE_SCHEMA, agentType: 'general-purpose' })
    .then(res => ({ ...res, reviewer: r.key }))
))

const flagged = reviews.filter(Boolean).flatMap(r =>
  (r.findings || []).filter(f => f.severity === 'critical' || f.severity === 'major')
    .map(f => ({ ...f, reviewer: r.reviewer }))
)

phase('Verify')
const VERDICT_SCHEMA = {
  type: 'object',
  properties: {
    is_real: { type: 'boolean', description: 'true if the issue is genuine and should be fixed' },
    reasoning: { type: 'string' },
    fix: { type: 'string', description: 'concrete recommended fix if real' },
  },
  required: ['is_real', 'reasoning'],
}

const verified = await parallel(flagged.map(f => () =>
  agent(`Adversarially verify this claimed issue in the NeSy study at ${ROOT}. Default to is_real=false unless you can confirm it with concrete evidence from the files/data. Issue (${f.severity}, from ${f.reviewer}) at ${f.location}: ${f.problem}\nClaimed evidence: ${f.evidence}\nConfirm or refute by reading the actual files / recomputing.`,
    { label: `verify:${f.location}`.slice(0, 40), phase: 'Verify', schema: VERDICT_SCHEMA, agentType: 'general-purpose' })
    .then(v => ({ ...f, verdict: v }))
))

const confirmed = verified.filter(Boolean).filter(f => f.verdict?.is_real)
return {
  n_reviewers: reviews.filter(Boolean).length,
  total_findings: reviews.filter(Boolean).reduce((a, r) => a + (r.findings?.length || 0), 0),
  n_flagged_major_critical: flagged.length,
  n_confirmed: confirmed.length,
  confirmed_issues: confirmed.map(f => ({ severity: f.severity, location: f.location, problem: f.problem, fix: f.verdict.fix })),
  reviewer_summaries: reviews.filter(Boolean).map(r => ({ reviewer: r.reviewer, summary: r.summary })),
}

